import React from "react";

function ProjectCard({ project, onDelete, showDelete = false }) {
  return (
    <div className="project-card">
      <div className="badge">Student Project</div>

      <h3>{project.title}</h3>

      <p>{project.description}</p>

      <p>
        <strong>Tech Stack:</strong> {project.techStack}
      </p>

      {project.createdBy?.name && (
        <p>
          <strong>By:</strong> {project.createdBy.name}
        </p>
      )}

      <div className="card-links">
        {project.githubLink && (
          <a
            href={project.githubLink}
            target="_blank"
            rel="noreferrer"
            className="card-link"
          >
            GitHub
          </a>
        )}

        {project.liveLink && (
          <a
            href={project.liveLink}
            target="_blank"
            rel="noreferrer"
            className="card-link"
          >
            Live Demo
          </a>
        )}
      </div>

      {showDelete && (
        <button className="delete-btn" onClick={() => onDelete(project._id)}>
          Delete Project
        </button>
      )}
    </div>
  );
}

export default ProjectCard;
